export interface Client {
  id: string;
  name: string;
  niche: string;
  status: string;
}

import React from 'react';

interface SidebarProps {
  activeTab: string;
  setActiveTab: (tab: string) => void;
}

export default function Sidebar({ activeTab, setActiveTab }: SidebarProps) {
  return (
    <aside className="w-64 border-r border-slate-800 bg-[#0a0a0a] p-4 flex flex-col">
      <h1 className="text-indigo-400 font-bold mb-6 text-xl tracking-tight">Dashboard</h1>
      <nav className="space-y-1">
        <button 
          onClick={() => setActiveTab('database')}
          className={`w-full text-left px-3 py-2 rounded-md transition-colors text-sm font-medium ${activeTab === 'database' ? 'bg-indigo-500/10 text-indigo-400 border border-indigo-500/20' : 'text-slate-400 hover:bg-slate-800 hover:text-slate-200'}`}
        >
          Client Database
        </button>
      </nav>
    </aside>
  );
}

import React, { useState, useMemo } from 'react';
import { Client } from './types';

interface DatabaseProps {
  clients: Client[];
}

export default function Database({ clients }: DatabaseProps) {
  const [search, setSearch] = useState('');

  const filtered = useMemo(() => {
    return clients.filter(c => 
      c.name.toLowerCase().includes(search.toLowerCase()) || 
      c.niche.toLowerCase().includes(search.toLowerCase())
    );
  }, [clients, search]);

  return (
    <div className="p-8 max-w-4xl mx-auto">
      <header className="mb-8">
        <h2 className="text-2xl font-bold text-slate-100 mb-4">Client Database</h2>
        <input 
          type="text" 
          placeholder="Search by name or niche..." 
          className="w-full px-4 py-2.5 bg-[#0a0a0a] border border-slate-800 focus:border-indigo-500 focus:ring-1 focus:ring-indigo-500 rounded-lg text-slate-200 placeholder-slate-500 outline-none transition-all"
          value={search}
          onChange={(e) => setSearch(e.target.value)}
        />
      </header>
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        {filtered.length > 0 ? (
          filtered.map(c => (
            <div key={c.id} className="p-5 bg-[#0a0a0a] border border-slate-800 hover:border-slate-700 rounded-xl transition-colors">
              <div className="flex justify-between items-start mb-2">
                <h3 className="font-semibold text-slate-100">{c.name}</h3>
                <span className={`text-xs font-medium px-2.5 py-1 rounded-full ${c.status === 'Live' ? 'bg-emerald-500/10 text-emerald-400' : 'bg-amber-500/10 text-amber-400'}`}>
                  {c.status}
                </span>
              </div>
              <p className="text-sm text-slate-400">{c.niche}</p>
            </div>
          ))
        ) : (
          <div className="col-span-full text-center py-12 text-slate-500">
            No clients found matching "{search}"
          </div>
        )}
      </div>
    </div>
  );
}

import React, { useState } from 'react';
import Sidebar from './Sidebar';
import Database from './Database';
import clientData from './clients.json';
import { Client } from './types';

export default function App() {
  const [activeTab, setActiveTab] = useState('database');
  const [clients] = useState<Client[]>(clientData);

  return (
    <div className="flex h-screen bg-[#050505] text-slate-200 font-sans">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} />
      <main className="flex-1 overflow-y-auto">
        {activeTab === 'database' && <Database clients={clients} />}
      </main>
    </div>
  );
}

